14	// newWorkStatusCommand creates the "ddx work status" subcommand: a
15	// project-scoped live-worker report.
16	//
17	// The default report lists only live `ddx work` / `ddx try` processes whose
18	// resolved project root matches the requested project. The earlier failure
19	// mode this command exists to prevent is a global `ps | grep ddx work` scan
20	// surfacing a worker from another repository while operators are asking
21	// about a specific project's queue.
22	func (f *CommandFactory) newWorkStatusCommand() *cobra.Command {
23		cmd := &cobra.Command{
24			Use:   "status",
25			Short: "Show live ddx workers scoped to this project",
26			Long: `status lists the live ddx worker processes (ddx work / ddx try)
27	whose project root matches the current project. The default scope is the
28	git root of the working directory; pass --project to override or
29	--all-projects to inspect every worker on the host.
30	
31	Workers from other repositories are intentionally excluded from the
32	default view. Reporting them as evidence that "the worker is still
33	running" hides whether the requested project's queue has stalled.
34	
35	Output columns (terminal):
36	  PID         — process id of the worker
37	  AGE         — wall-clock age since the worker process started
38	  COMMAND     — the worker's command line (truncated for terminals)
39	  BEAD        — active bead id when it can be inferred from argv or the
40	                isolated execute-bead worktree
41	  WORKTREE    — execute-bead worktree path when the worker is inside one
42	
43	JSON output preserves the full set of fields including project_root.`,
44			Example: `  # Show live workers for the current project
45	  ddx work status
46	
47	  # JSON for piping to jq
48	  ddx work status --json
49	
50	  # Explicit cross-project view
51	  ddx work status --all-projects --json`,
52			Args: cobra.NoArgs,
53			RunE: f.runWorkStatus,
54		}
55		cmd.Flags().String("project", "", "Target project root path (default: CWD git root). Env: DDX_PROJECT_ROOT")
56		cmd.Flags().Bool("all-projects", false, "Report workers from every project; opt-in escape hatch")
57		cmd.Flags().Bool("json", false, "Output as JSON")
58		return cmd
59	}
60	
61	// workerStatusScanner is set by tests via the CommandFactory to inject a
62	// deterministic worker set without spawning real processes.
63	type workerStatusScanner = workerstatus.Scanner
64	
65	// WorkStatusReport is the JSON payload emitted by `ddx work status --json`.
66	type WorkStatusReport struct {
67		ProjectRoot string                    `json:"project_root,omitempty"`
68		Scope       string                    `json:"scope"`
69		Workers     []workerstatus.LiveWorker `json:"workers"`
70	}
71	
72	func (f *CommandFactory) runWorkStatus(cmd *cobra.Command, _ []string) error {
73		projectFlag, _ := cmd.Flags().GetString("project")
74		allProjects, _ := cmd.Flags().GetBool("all-projects")
75		asJSON, _ := cmd.Flags().GetBool("json")
76	
77		projectRoot := resolveProjectRoot(projectFlag, f.WorkingDir)
78	
79		scanner := f.workerScanner()
80		all, err := scanner.Scan(cmd.Context())
81		if err != nil {
82			return fmt.Errorf("scan live workers: %w", err)
83		}
84	
85		report := WorkStatusReport{
86			ProjectRoot: projectRoot,
87			Scope:       "project",
88			Workers:     filterAndSortWorkers(all, projectRoot, allProjects),
89		}
90		if allProjects {
91			report.Scope = "all-projects"
92		}
93	
94		out := cmd.OutOrStdout()
95		if asJSON {
96			return writeWorkStatusJSON(out, report)
97		}
98		writeWorkStatusText(out, report)
99		return nil
100	}
101	
102	func (f *CommandFactory) workerScanner() workerStatusScanner {
103		if f.workerScannerOverride != nil {
104			return f.workerScannerOverride
105		}
106		return workerstatus.New()
107	}
108	
109	func filterAndSortWorkers(all []workerstatus.LiveWorker, projectRoot string, allProjects bool) []workerstatus.LiveWorker {
110		var filtered []workerstatus.LiveWorker
111		if allProjects {
112			filtered = append(filtered, all...)
113		} else {
114			filtered = workerstatus.FilterByProject(all, projectRoot)
115		}
116		sort.SliceStable(filtered, func(i, j int) bool {
117			if filtered[i].StartedAt.Equal(filtered[j].StartedAt) {
118				return filtered[i].PID < filtered[j].PID
119			}
120			return filtered[i].StartedAt.Before(filtered[j].StartedAt)
121		})
122		return filtered
123	}
124	
125	func writeWorkStatusJSON(out io.Writer, report WorkStatusReport) error {
126		if report.Workers == nil {
127			report.Workers = []workerstatus.LiveWorker{}
128		}
129		enc := json.NewEncoder(out)
130		enc.SetIndent("", "  ")
131		return enc.Encode(report)
132	}
133	
134	func writeWorkStatusText(out io.Writer, report WorkStatusReport) {
135		if len(report.Workers) == 0 {
136			if report.Scope == "all-projects" {
137				fmt.Fprintln(out, "No live ddx workers found on this host.")
138				return
139			}
140			fmt.Fprintf(out, "No live ddx workers for project %s.\n", report.ProjectRoot)
141			return
142		}
143		if report.Scope == "all-projects" {
144			fmt.Fprintf(out, "live ddx workers (all projects): %d\n", len(report.Workers))
145		} else {
146			fmt.Fprintf(out, "live ddx workers for %s: %d\n", report.ProjectRoot, len(report.Workers))
147		}
148		for _, w := range report.Workers {
149			bead := w.BeadID
150			if bead == "" {
151				bead = "-"
152			}
153			worktree := w.ExecutionWorktree
154			if worktree == "" {
155				worktree = "-"
156			}
157			fmt.Fprintf(out, "  pid=%d age=%s project=%s bead=%s worktree=%s\n    %s\n",
158				w.PID, w.Age, w.ProjectRoot, bead, worktree, w.Command)
159		}
160	}
