1	// Package workerstatus reports on live "ddx work" / "ddx try" processes,
2	// scoped to a specific project root by default.
3	//
4	// Operators and agents asking "is the worker still working beads?" must be
5	// able to answer the question for one project at a time. A global process
6	// scan ("ps aux | grep ddx work") returns workers from every checkout on the
7	// machine and produces a misleading "yes, working" signal when the worker
8	// belongs to a different repository. This package filters live workers by
9	// the resolved project root so the answer always matches the question.
10	package workerstatus
11	
12	import (
13		"context"
14		"path/filepath"
15		"regexp"
16		"strings"
17		"time"
18	)
19	
20	// LiveWorker describes one running ddx worker process.
21	type LiveWorker struct {
22		PID               int       `json:"pid"`
23		Command           string    `json:"command"`
24		StartedAt         time.Time `json:"started_at"`
25		AgeSeconds        float64   `json:"age_seconds"`
26		Age               string    `json:"age"`
27		ProjectRoot       string    `json:"project_root"`
28		BeadID            string    `json:"bead_id,omitempty"`
29		ExecutionWorktree string    `json:"execution_worktree,omitempty"`
30		Cwd               string    `json:"cwd,omitempty"`
31	}
32	
33	// Scanner discovers live ddx worker processes on the host.
34	type Scanner interface {
35		Scan(ctx context.Context) ([]LiveWorker, error)
36	}
37	
38	// New returns the platform-appropriate Scanner. On Linux this reads /proc.
39	// On other platforms it returns an empty list; the caller's tests and the
40	// --all-projects escape hatch remain meaningful regardless.
41	func New() Scanner {
42		return newSystemScanner()
43	}
44	
45	// beadIDPattern matches ddx-style bead identifiers (prefix + hex, 8+ chars
46	// total) embedded in argv strings or worktree paths.
47	var beadIDPattern = regexp.MustCompile(`\bddx-[a-f0-9]{8}\b`)
48	
49	// executionWorktreePattern matches the conventional execute-bead worktree
50	// directory name (`.execute-bead-wt-<bead>-<timestamp>-<suffix>`) anywhere
51	// in a path. The directory name is enough to identify the worktree even when
52	// the surrounding path is unconventional.
53	var executionWorktreePattern = regexp.MustCompile(`(?:^|/)(\.execute-bead-wt-[^/]+)`)
54	
55	// InferBead extracts a bead ID and execution worktree path from the worker's
56	// command line and current working directory. It returns the longest worktree
57	// path that contains a `.execute-bead-wt-*` segment (typically the cwd, when
58	// the inline worker has chdir'd into the isolated worktree), and the first
59	// bead ID matched in either the command line or the worktree path.
60	//
61	// Either return value may be empty when no signal is present, which is the
62	// expected case for a long-running `ddx work` drain that has not yet started
63	// a specific bead.
64	func InferBead(cmdline, cwd string) (beadID, worktree string) {
65		worktree = extractWorktreePath(cwd)
66		if worktree == "" {
67			worktree = extractWorktreePath(cmdline)
68		}
69	
70		if m := beadIDPattern.FindString(worktree); m != "" {
71			beadID = m
72		}
73		if beadID == "" {
74			if m := beadIDPattern.FindString(cmdline); m != "" {
75				beadID = m
76			}
77		}
78		if beadID == "" {
79			if m := beadIDPattern.FindString(cwd); m != "" {
80				beadID = m
81			}
82		}
83		return beadID, worktree
84	}
85	
86	func extractWorktreePath(s string) string {
87		if s == "" {
88			return ""
89		}
90		if !strings.Contains(s, ".execute-bead-wt-") {
91			return ""
92		}
93		matches := executionWorktreePattern.FindStringIndex(s)
94		if matches == nil {
95			return ""
96		}
97		end := matches[1]
98		for end < len(s) {
99			r := s[end]
100			if r == ' ' || r == '\x00' || r == '\t' {
101				break
102			}
103			end++
104		}
105		return s[:end]
106	}
107	
108	// FilterByProject returns workers whose ProjectRoot resolves to the same path
109	// as projectRoot. Resolution canonicalises both sides via filepath.Abs and
110	// filepath.EvalSymlinks so a symlinked checkout matches its real path.
111	func FilterByProject(workers []LiveWorker, projectRoot string) []LiveWorker {
112		target := canonicalPath(projectRoot)
113		out := make([]LiveWorker, 0, len(workers))
114		for _, w := range workers {
115			if SamePath(w.ProjectRoot, target) {
116				out = append(out, w)
117			}
118		}
119		return out
120	}
121	
122	// SamePath reports whether a and b refer to the same on-disk location after
123	// canonicalisation. It tolerates empty inputs (returning false) so callers
124	// can safely compare optional fields without prefiltering.
125	func SamePath(a, b string) bool {
126		ca := canonicalPath(a)
127		cb := canonicalPath(b)
128		if ca == "" || cb == "" {
129			return false
130		}
131		return ca == cb
132	}
133	
134	func canonicalPath(p string) string {
135		if strings.TrimSpace(p) == "" {
136			return ""
137		}
138		abs, err := filepath.Abs(p)
139		if err != nil {
140			abs = filepath.Clean(p)
141		}
142		if resolved, err := filepath.EvalSymlinks(abs); err == nil {
143			return resolved
144		}
145		return abs
146	}
147	
148	// FormatAge renders a duration as a short human-readable string mirroring
149	// the conventions used by the server-backed worker list (`5s`, `12m`,
150	// `1h30m`). It is intended for terminal output; JSON output uses
151	// AgeSeconds as the numeric source of truth.
152	func FormatAge(d time.Duration) string {
153		if d < time.Minute {
154			if d < 0 {
155				d = 0
156			}
157			return roundedSeconds(d)
158		}
159		if d < time.Hour {
160			return roundedMinutes(d)
161		}
162		hours := int(d.Hours())
163		mins := int(d.Minutes()) % 60
164		if mins == 0 {
165			return durationHours(hours)
166		}
167		return durationHoursMinutes(hours, mins)
168	}
169	
170	func roundedSeconds(d time.Duration) string {
171		secs := int(d.Seconds())
172		return durationSeconds(secs)
173	}
174	
175	func roundedMinutes(d time.Duration) string {
176		mins := int(d.Minutes())
177		return durationMinutes(mins)
178	}
179	
180	func durationSeconds(n int) string { return formatUnit(n, "s") }
181	func durationMinutes(n int) string { return formatUnit(n, "m") }
182	func durationHours(n int) string   { return formatUnit(n, "h") }
183	func durationHoursMinutes(h, m int) string {
184		return formatUnit(h, "h") + formatUnit(m, "m")
185	}
186	
187	func formatUnit(n int, unit string) string {
188		if n < 0 {
189			n = 0
190		}
191		return itoa(n) + unit
192	}
193	
194	func itoa(n int) string {
195		if n == 0 {
196			return "0"
197		}
198		neg := n < 0
199		if neg {
200			n = -n
201		}
202		var digits [20]byte
203		i := len(digits)
204		for n > 0 {
205			i--
206			digits[i] = byte('0' + n%10)
207			n /= 10
208		}
209		out := string(digits[i:])
210		if neg {
211			return "-" + out
212		}
213		return out
214	}
