361	func (s *ServerState) GetWorkerProgressGraphQL(id string) []*ddxgraphql.PhaseTransition {
362		if s.workingDir == "" {
363			return nil
364		}
365		data, err := os.ReadFile(filepath.Join(s.workingDir, ".ddx", "workers", id, "status.json"))
366		if err != nil {
367			return nil
368		}
