2801	// writeLoopEvent emits one structured JSONL line to sink describing a
2802	// milestone in an execute-bead loop run. Entries use the same envelope as
2803	// the Fizeau harness (session_id/seq/type/ts/data) so existing event
2804	// consumers can parse the stream uniformly. Errors are swallowed:
2805	// structured logging must never break the core execute-loop.
2806	func writeLoopEvent(sink io.Writer, sessionID, eventType string, data map[string]any, ts time.Time) {
2807		if sink == nil {
2808			return
2809		}
2810		if data == nil {
2811			data = map[string]any{}
2812		}
2813		entry := map[string]any{
2814			"session_id": sessionID,
2815			"type":       eventType,
2816			"ts":         ts.UTC().Format(time.RFC3339Nano),
2817			"data":       data,
2818		}
2819		line, err := json.Marshal(entry)
2820		if err != nil {
2821			return
2822		}
2823		frame := make([]byte, len(line)+1)
2824		copy(frame, line)
2825		frame[len(line)] = '\n'
2826		_, _ = sink.Write(frame)
2827	}
